import React, { useEffect, useRef, useState } from 'react';
import { useHistory, useLocation } from 'react-router-dom';
// import '../styles/AuthForm.css';

const OtpVerification = () => {
    const [data, setData] = useState(["", "", "", "", "", ""]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');
    const navigate = useHistory();
    const inputRef = useRef([]);
    const location = useLocation();

    const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
    const validValue = data.every(el => el);

    useEffect(() => {
        if (!location?.state?.email) {
            navigate.push("/");
        }
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setMessage('');
        setIsLoading(true);

        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/verify-otp`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    otp: data.join(""),
                    email: location?.state?.email
                })
            });

            const result = await response.json();

            if (!response.ok) {
                throw new Error(result.message || 'OTP verification failed');
            }

            setMessage('OTP verified successfully!');
            setTimeout(() => {
                navigate.push("/reset-password", {
                    state: {
                        data: result,
                        email: location?.state?.email
                    }
                });
            }, 1500);

        } catch (error) {
            console.error('OTP verification error:', error);
            setError(error.message || 'Failed to verify OTP. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleInputChange = (e, index) => {
        const value = e.target.value;
        
        if (value.length > 1) return; // Prevent multiple characters
        
        const newData = [...data];
        newData[index] = value;
        setData(newData);

        // Auto-focus next input
        if (value && index < 5) {
            inputRef.current[index + 1]?.focus();
        }
    };

    const handleKeyDown = (e, index) => {
        // Handle backspace to go to previous input
        if (e.key === 'Backspace' && !data[index] && index > 0) {
            inputRef.current[index - 1]?.focus();
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-form-wrapper">
                <div className="auth-header">
                    <div className="login-logo">
                        <div className="ring-container">
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="logo-text">FORUM ACADEMY</div>
                        </div>
                    </div>
                    <h2>Enter OTP</h2>
                    <p>We've sent a 6-digit code to {location?.state?.email}</p>
                </div>

                {error && (
                    <div className="form-error modern">
                        <span className="material-icons">error_outline</span>
                        <span>{error}</span>
                    </div>
                )}

                {message && (
                    <div className="form-success modern">
                        <span className="material-icons">check_circle</span>
                        <span>{message}</span>
                    </div>
                )}

                <form className="auth-form" onSubmit={handleSubmit}>
                    <div className="otp-container">
                        <label htmlFor="otp">Enter Your OTP:</label>
                        <div className="otp-inputs">
                            {data.map((element, index) => (
                                <input
                                    key={"otp" + index}
                                    type="text"
                                    ref={(ref) => {
                                        inputRef.current[index] = ref;
                                        return ref;
                                    }}
                                    value={data[index]}
                                    onChange={(e) => handleInputChange(e, index)}
                                    onKeyDown={(e) => handleKeyDown(e, index)}
                                    maxLength={1}
                                    className="otp-input"
                                    autoFocus={index === 0}
                                />
                            ))}
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={!validValue || isLoading}
                        className={`auth-button ${validValue ? 'enabled' : 'disabled'}`}
                    >
                        {isLoading ? (
                            <>
                                <span className="button-loader"></span>
                                <span>Verifying...</span>
                            </>
                        ) : (
                            <>
                                <span>Verify OTP</span>
                                <span className="material-icons button-icon">check</span>
                            </>
                        )}
                    </button>
                </form>

                <div className="auth-footer">
                    <p>
                        Didn't receive the code?{' '}
                        <button
                            type="button"
                            className="link-button"
                            onClick={() => {
                                // Implement resend OTP logic here
                                console.log('Resend OTP');
                            }}
                        >
                            Resend OTP
                        </button>
                    </p>
                    <p>
                        Back to{' '}
                        <button
                            type="button"
                            className="link-button"
                            onClick={() => navigate.push("/")}
                        >
                            Login
                        </button>
                    </p>
                </div>
            </div>
        </div>
    );
};

export default OtpVerification;
